Custom CSS:
.board .reply {
  background-color: transparent;
  border-color: #ccc transparent transparent transparent;
  border-style: solid;
  border-radius: 0 !important;
  margin-bottom: 0;
}
#themes {
  text-shadow: none;
}
#qp {
  text-shadow: 1px 0 0 rgb(0,0,0),
    1px 1px 0 rgb(0,0,0),
    0 1px 0 rgb(0,0,0),
    1px 1px 2px rgb(0,0,0);
}
#qp .op.post,
#qp .reply.post {
  border: 1px rgba(0,0,0,0.7) solid;
  background: linear-gradient(to right, rgba(0,0,0,0.7), rgba(0,0,0,0.5)), transparent;
}
#qp div.post,
#qp .pln,
#qp .postNum a {
  color: #fcd;
}
#qp .dateTime {
  color: #fcd !important;
}
#qp .subject,
#qp .nameBlock > .useremail > .name,
#qp .nameBlock > .useremail > .postertrip,
#qp .name,
#qp .postertrip,
#qp .trip {
  color: #ffaac0 !important;
}
#qp a {
  color: #aaaac8;
}
.boardBanner a,
#qp a.backlink,
#qp span.quote > a.quotelink {
  color: rgb(255,255,255);
}
#qp span.quote {
  color: rgb(130,163,100);
}
.board {
  box-shadow: 0 20px 40px 10px rgba(0,0,0,0.1);
  border-radius: 4px;
}
:not(#themes) .rice {
  box-shadow:rgba(170, 170, 170,0.3) 0 1px;
}
#qp .prettyprint {
  background-color: rgba(0,0,0,0.3);
  border: 1px solid rgba(0,0,0,0.5);
}
#qp span.tag {
  color: #96562c;
}
#qp span.pun {
  color: #5b6f2a;
}
#qp span.com {
  color: #a34443;
}
#qp span.str,
#qp span.atv {
  color: #8ba446;
}
#qp span.kwd {
  color: #987d3e;
}
#qp span.typ,
#qp span.atn {
  color: #897399;
}
#qp span.lit {
  color: #558773;
}
